package main; import ("context"; "fmt"; "log"; "github.com/jackc/pgx/v5"); func main() { conn, err := pgx.Connect(context.Background(), "postgres://postgres:postgres@localhost:5432/shiftmaster?sslmode=disable"); if err != nil { log.Fatal(err) }; defer conn.Close(context.Background()); rows, _ := conn.Query(context.Background(), "SELECT employee_code, role, status FROM employees"); for rows.Next() { var c, r, s string; rows.Scan(&c, &r, &s); fmt.Printf("%s | %s | %s`n", c, r, s) } }
